/*****************************************
 * Calculate Percentage of Mandate Amount
 * 
 * by Cinthia Romero
 ****************************************/
var initialAmount = this._parent.PE_MANDATE_INITIAL_TOTAL_AMOUNT;
var mandateAmount = this.PE_MANDATE_AMOUNT;
var percentageValue = 0;
if (initialAmount != "" && initialAmount != undefined && initialAmount != null && initialAmount != 0 && mandateAmount != "" && mandateAmount != undefined && mandateAmount != null) {
    percentageValue = (mandateAmount * 100) / initialAmount;
}
return percentageValue;

/*****************************************
 * Return LABEL 
 * 
 * by Elmer Orihuela
 ****************************************/
return this.PE_MANDATE_NAME_SL ? this.PE_MANDATE_NAME_SL.LABEL : "";

/*****************************************
 * Return COMPLETE_NAME 
 * 
 * by Elmer Orihuela
 ****************************************/
return this.PE_MANDATE_NAME_SL ? this.PE_MANDATE_NAME_SL.COMPLETE_NAME : "";

/*****************************************
 * Calculate Percentage of Mandate Amount
 * 
 * by Cinthia Romero
* modified by Adriana Centellas
 ****************************************/
var initialAmount = this._parent.PE_MANDATE_INITIAL_TOTAL_AMOUNT;
var mandateAmount = this.PE_MANDATE_AMOUNT;
var percentageValue = "0.00";

if (
    initialAmount !== "" && initialAmount !== undefined && initialAmount !== null && initialAmount !== 0 &&
    mandateAmount !== "" && mandateAmount !== undefined && mandateAmount !== null
) {
    percentageValue = ((mandateAmount * 100) / initialAmount).toFixed(2);
}

return percentageValue;
